\relinput{Figures/Q04a.tex}
\AnswerLine[][]
\Marks{3}

\item On the grid, draw the image of shape $A$ after a rotation, 90$^\circ$ anticlockwise, centre (5, 1).
\relinput{Figures/Q04b.tex}
\AnswerLine[][]
