\noindent\textbf{[2024 Oct/Nov, 0580/31, Question 5]}\par

\begin{parts}
\item The scatter diagram shows the distance travelled and the cost for each of 12 taxi journeys.
\relinput{Figures/Q05a.tex}

\begin{subparts}
    \item `The scatter diagram shows positive correlation.' \\
    Is this statement true or false? \\
    Give a reason for your answer.
    \AnswerLine[][\dots \text{ because } \dots]
    \Marks{1}

    \item On one journey, the cost per kilometre travelled was much more expensive than on all of the other journeys. \\
    Draw a ring around this point on the scatter diagram.
    \Marks{1}

    \item Draw a line of best fit on the scatter diagram.
    \Marks{1}

    \item Another journey is 8~km long. \\
    Use your line of best fit to find an estimate for the cost of this journey.
    \AnswerLine[\$][]
    \Marks{1}
\end{subparts}

\item Arit, Luke and Marie share the cost of a taxi journey. \\
The cost is \$26.40.

\begin{subparts}
    \item Calculate how much Arit pays if they share the cost equally.
    \AnswerLine[\$][]
    \Marks{1}

    \item They decide to share the cost in proportion to the distance they each travel in the taxi. \\
    Arit travels 12~km, Luke travels 3~km and Marie travels 7.5~km.
    \begin{subsubparts}
        \item Write the ratio $12 : 3 : 7.5$ in its simplest form.
        \AnswerLine[][\dots : \dots : \dots]
        \Marks{2}

        \item Calculate how much more Arit pays than if they share the cost equally.
        \AnswerLine[\$][]
        \Marks{3}
    \end{subsubparts}
\end{subparts}

\item Jin invests some money from his taxi company. \\
He invests \$18~600 at a rate of 1.7\% per year compound interest. \\
Calculate the value of the investment at the end of 6 years. \\
Give your answer correct to the nearest dollar.
\AnswerLine[\$][]
\Marks{3}
\end{parts}

